// Generate unique identifiers
const timestamp = Date.now();
const qrCode = `BUS-${timestamp}-JOURNEY`;
const sessionId = `journey-${timestamp}`;

// Store in flow context
flow.set('journeyQR', qrCode);
flow.set('journeySession', sessionId);
flow.set('journeyStartTime', timestamp);

node.warn('\n🎬 ===== MASTER SIMULATION STARTING =====\n');
node.warn('📱 Make sure your Android emulator is visible!');
node.warn(`🎫 QR Code: ${qrCode}`);
node.warn(`🗺️ Session: ${sessionId}\n`);

msg.payload = {
    qr_code: qrCode,
    session_id: sessionId,
    step: 'init'
};

return msg;

node.warn('\n📍 STEP 1: DESTINATION SELECTION');
node.warn('   Opening destination selection screen...');
node.status({fill:"blue", shape:"dot", text:"Step 1: Destination"});

const deepLink = 'smartbusapp://navigate?screen=destination';
const adbCommand = `adb shell am start -a android.intent.action.VIEW -d "${deepLink}"`;

msg.adbCommand = adbCommand;
msg.deepLink = deepLink;
msg.step = 'destination';

node.warn(`   ADB: ${adbCommand}\n`);

return msg;

node.warn('\n💳 STEP 2: PAYMENT SELECTION');
node.warn('   Opening payment screen...');
node.status({fill:"green", shape:"dot", text:"Step 2: Payment"});

const deepLink = 'smartbusapp://navigate?screen=payment';
const adbCommand = `adb shell am start -a android.intent.action.VIEW -d "${deepLink}"`;

msg.adbCommand = adbCommand;
msg.deepLink = deepLink;
msg.step = 'payment';

node.warn(`   ADB: ${adbCommand}\n`);

return msg;

node.warn('\n✅ STEP 3: TRIP CONFIRMATION');
node.warn('   Opening confirmation screen...');
node.status({fill:"green", shape:"ring", text:"Step 3: Confirmation"});

const deepLink = 'smartbusapp://navigate?screen=confirmation';
const adbCommand = `adb shell am start -a android.intent.action.VIEW -d "${deepLink}"`;

msg.adbCommand = adbCommand;
msg.deepLink = deepLink;
msg.step = 'confirmation';

node.warn(`   ADB: ${adbCommand}\n`);

return msg;

node.warn('\n🚌 Journey in progress...');
node.warn('   Choose scenario ending:');
node.warn('   - Click "Approaching Destination" for normal ending');
node.warn('   - Click "Missed Destination" for missed stop');
node.warn('   - Click "Bus Break" for rest stop scenario\n');

node.status({fill:"yellow", shape:"dot", text:"Journey in progress"});

msg.payload = {
    status: 'journey_active',
    message: 'Choose ending scenario'
};

return msg;

node.warn('\n🔔 APPROACHING DESTINATION');
node.warn('   Showing proximity alert...');
node.status({fill:"orange", shape:"ring", text:"Approaching destination"});

const deepLink = 'smartbusapp://simulate?type=approaching&destination=Harare&distance=500';
const adbCommand = `adb shell am start -a android.intent.action.VIEW -d "${deepLink}"`;

msg.adbCommand = adbCommand;
msg.deepLink = deepLink;
msg.step = 'approaching';

node.warn(`   ADB: ${adbCommand}\n`);

return msg;

node.warn('\n🚪 STEP 4: DISEMBARK');
node.warn('   Opening disembark screen...');
node.status({fill:"green", shape:"dot", text:"Step 4: Disembark"});

const deepLink = 'smartbusapp://navigate?screen=disembark';
const adbCommand = `adb shell am start -a android.intent.action.VIEW -d "${deepLink}"`;

msg.adbCommand = adbCommand;
msg.deepLink = deepLink;
msg.step = 'disembark';

node.warn(`   ADB: ${adbCommand}\n`);

return msg;

const startTime = flow.get('journeyStartTime');
const duration = Math.round((Date.now() - startTime) / 1000);

node.warn('\n🎉 ===== JOURNEY COMPLETE! =====');
node.warn(`   Total duration: ${duration} seconds`);
node.warn(`   Scenario: Approaching → Disembark`);
node.warn('   ✅ All steps executed successfully!\n');

node.status({fill:"green", shape:"ring", text:"Complete!"});

msg.payload = {
    status: 'complete',
    duration: duration,
    scenario: 'approaching_disembark'
};

return msg;

node.warn('\n⚠️ MISSED DESTINATION');
node.warn('   Showing missed stop alert...');
node.status({fill:"red", shape:"ring", text:"Missed destination!"});

const deepLink = 'smartbusapp://simulate?type=missed&destination=Harare';
const adbCommand = `adb shell am start -a android.intent.action.VIEW -d "${deepLink}"`;

msg.adbCommand = adbCommand;
msg.deepLink = deepLink;
msg.step = 'missed';

node.warn(`   ADB: ${adbCommand}\n`);

return msg;

const startTime = flow.get('journeyStartTime');
const duration = Math.round((Date.now() - startTime) / 1000);

node.warn('\n⚠️ ===== MISSED DESTINATION SCENARIO COMPLETE =====');
node.warn(`   Total duration: ${duration} seconds`);
node.warn(`   Scenario: Missed Stop Alert`);
node.warn('   ✅ Passenger notified to alert driver\n');

node.status({fill:"yellow", shape:"ring", text:"Missed scenario complete"});

msg.payload = {
    status: 'complete',
    duration: duration,
    scenario: 'missed_destination'
};

return msg;

node.warn('\n🚻 BUS BREAK SCENARIO');
node.warn('   Opening bus break screen...');
node.status({fill:"yellow", shape:"dot", text:"Bus break"});

const deepLink = 'smartbusapp://navigate?screen=bus-break';
const adbCommand = `adb shell am start -a android.intent.action.VIEW -d "${deepLink}"`;

msg.adbCommand = adbCommand;
msg.deepLink = deepLink;
msg.step = 'bus-break';

node.warn(`   ADB: ${adbCommand}\n`);

return msg;

node.warn('\n🚌 Passenger returning to bus...');
node.status({fill:"green", shape:"dot", text:"Returning to bus"});

// Simulate validation when returning
node.warn('   Simulating QR validation on return...\n');

msg.payload = {
    action: 'return_from_break',
    message: 'Passenger back on bus'
};

return msg;

const startTime = flow.get('journeyStartTime');
const duration = Math.round((Date.now() - startTime) / 1000);

node.warn('\n🚻 ===== BUS BREAK SCENARIO COMPLETE =====');
node.warn(`   Total duration: ${duration} seconds`);
node.warn(`   Scenario: Bus Break (Out & In)`);
node.warn('   ✅ Passenger tracked during rest stop\n');

node.status({fill:"green", shape:"ring", text:"Break complete"});

msg.payload = {
    status: 'complete',
    duration: duration,
    scenario: 'bus_break'
};

return msg;
